from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check Jira state"}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}
    with open(jira_path) as f:
        data = json.load(f)

    # Pre-existing issues that were present before the agent started
    pre_existing_keys = {
        "MCA_APPEALS-1", "MCA_APPEALS-2", "MCA_APPEALS-3",
        "MCA_APPEALS-4", "MCA_APPEALS-5"
    }

    issues = data.get("issues", {})

    # Find any new issue (not in the pre-existing set) — the MCP tool assigns
    # the key based on project issue count, so it may be MCA-APPEALS-6, MCA-6,
    # CASE-1, or similar depending on which project key the agent used.
    new_issues = {k: v for k, v in issues.items() if k not in pre_existing_keys}

    if not new_issues:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": (
                "No new Jira ticket found beyond pre-existing issues "
                "(MCA_APPEALS-1 through 90). A new Jira ticket must be "
                "created with required case information."
            )
        }

    # Take the first (should be only one) new issue found
    ticket_key, ticket = next(iter(new_issues.items()))

    # Collect all text from the ticket recursively
    def collect_text(obj):
        texts = []
        if isinstance(obj, str):
            texts.append(obj)
        elif isinstance(obj, dict):
            for v in obj.values():
                texts.extend(collect_text(v))
        elif isinstance(obj, list):
            for item in obj:
                texts.extend(collect_text(item))
        elif obj is not None:
            texts.append(str(obj))
        return texts

    all_text = " ".join(collect_text(ticket)).lower()

    # Check for required terms (case-insensitive)
    # Rubric: at least 3 of these 5 terms
    required_terms = {
        "MBR-2026-04471": ["mbr-2026-04471", "mbr202604471", "mbr 2026 04471", "04471"],
        "88500": ["88500", "88,500", "88500.00", "$88,500", "$88500"],
        "parity": ["parity", "mhpaea"],
        "Dr. Ontario": ["ontario"],
        "concurrent care": ["concurrent"],
    }

    found_terms = []
    missing_terms = []
    for term_label, variants in required_terms.items():
        term_found = any(variant in all_text for variant in variants)
        if term_found:
            found_terms.append(term_label)
        else:
            missing_terms.append(term_label)

    # Rubric requires at least 3 of 5 terms
    min_required = 3
    total_terms = len(required_terms)
    score = len(found_terms) / total_terms

    if len(found_terms) >= min_required:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": (
                f"New Jira ticket ({ticket_key}) found with {len(found_terms)}/{total_terms} "
                f"required terms present: {', '.join(found_terms)}."
                + (f" Missing: {', '.join(missing_terms)}." if missing_terms else "")
            )
        }
    else:
        return {
            "pass": False,
            "score": score,
            "feedback": (
                f"New Jira ticket ({ticket_key}) found but only {len(found_terms)}/{min_required} "
                f"required terms present (need at least {min_required}). "
                f"Found: {', '.join(found_terms) if found_terms else 'none'}. "
                f"Missing: {', '.join(missing_terms)}."
            )
        }

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check mailbox"}
    mail_path = Path(external_services_path) / "mailbox.json"
    if not mail_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}
    with open(mail_path) as f:
        data = json.load(f)
    emails = data.get("emails", [])
    sent_emails = [e for e in emails if e.get("folder", "").lower() in ["sent", "sent items", "sent mail"]]
    if not sent_emails:
        return {"pass": False, "score": 0.0, "feedback": "No sent emails found in mailbox.json"}

    # We need to find a sent email that:
    # 1. Is addressed to Desert Springs Recovery Center
    # 2. References MCA-APPEALS-91 (which maps to CASE-2026-00091 or similar)
    # 3. Uses Template A-1
    # 4. Contains expedited header block with:
    #    - 'Expedited Basis: Treating Physician Certification'
    #    - 'Decision Due By: 2026-04-16 12:00 PM PT'

    best_match = None
    best_missing = None

    for email in sent_emails:
        body_full = email.get("body_text", "") or ""
        body_lower = body_full.lower()
        to_addr = (email.get("to_addr", "") or "").lower()
        subject = (email.get("subject", "") or "").lower()
        combined_lower = body_lower + " " + subject + " " + to_addr

        # Check reference to MCA-APPEALS-91 (accept various formats)
        has_case_ref = False
        case_patterns = [
            "mca-appeals-91", "mca-appeals-091", "mca-appeals-0091",
            "case-2026-00091", "case-2026-0091", "case-2026-091", "case-2026-91",
            "appeals-91", "appeals-091", "appeals-0091", "appeals-00091",
            "91"
        ]
        # Be generous: check for any reasonable reference
        for pat in case_patterns[:-1]:  # skip bare "91" unless nothing else matches
            if pat in combined_lower:
                has_case_ref = True
                break
        if not has_case_ref:
            # Check with regex for appeal/case number 91
            if re.search(r'(mca|case|appeal)[^a-z0-9]*0*91', combined_lower):
                has_case_ref = True
        if not has_case_ref:
            continue

        # Check Desert Springs Recovery Center as recipient
        is_to_desert_springs = False
        if "desert" in to_addr and "spring" in to_addr:
            is_to_desert_springs = True
        elif "desertspring" in to_addr:
            is_to_desert_springs = True
        elif "desert springs" in combined_lower:
            is_to_desert_springs = True
        elif "desert" in to_addr:
            is_to_desert_springs = True  # generous
        if not is_to_desert_springs:
            continue

        # Now check the specific required content
        missing = []

        # Check for expedited basis: treating physician certification
        if "treating physician certification" in body_lower:
            pass  # exact match
        elif "treating physician" in body_lower and "certification" in body_lower:
            pass  # close enough
        elif "treating physician" in body_lower:
            pass  # lenient
        else:
            missing.append("Expedited Basis: Treating Physician Certification")

        # Check for Decision Due By: 2026-04-16 12:00 PM PT
        has_date = ("2026-04-16" in body_full or "04/16/2026" in body_full or 
                    "april 16" in body_lower or "04-16-2026" in body_full or
                    "4/16/2026" in body_full or "april 16, 2026" in body_lower)
        if not has_date:
            missing.append("Decision Due By date (2026-04-16)")

        has_time = ("12:00 pm" in body_lower or "12:00pm" in body_lower or 
                    "12 pm" in body_lower or "12pm" in body_lower or
                    "noon" in body_lower or "12:00 PM" in body_full or
                    "12:00" in body_full)
        if not has_time:
            missing.append("Decision Due By time (12:00 PM)")

        # Check for expedited keyword
        if "expedited" not in body_lower:
            missing.append("Expedited header/keyword")

        # Check for Template A-1 reference (lenient - could be in subject or body)
        has_template = ("a-1" in combined_lower or "template a" in combined_lower or
                        "a1" in combined_lower or "template" in combined_lower)
        if not has_template:
            # Don't require explicit template mention if the content matches the template format
            pass  # Be lenient - the template content matters more than naming it

        # Allow up to 1 missing element for leniency
        if len(missing) == 0:
            return {"pass": True, "score": 1.0, "feedback": f"Found sent email to Desert Springs Recovery Center referencing MCA-APPEALS-91 with expedited header block containing Treating Physician Certification and Decision Due By 2026-04-16 12:00 PM PT. To: {email.get('to_addr', '')}"}
        elif best_match is None or len(missing) < len(best_missing):
            best_match = email
            best_missing = missing

    # If we found a close match with only 1 missing element, pass with partial credit
    if best_match is not None and len(best_missing) <= 1:
        return {"pass": True, "score": 0.8, "feedback": f"Found sent email to Desert Springs Recovery Center referencing MCA-APPEALS-91 with most expedited header fields. Minor missing: {', '.join(best_missing)}. To: {best_match.get('to_addr', '')}"}

    if best_match is not None:
        return {"pass": False, "score": 0.0, "feedback": f"Found a sent email to Desert Springs with case reference, but missing required expedited header fields: {', '.join(best_missing)}. To: {best_match.get('to_addr', '')}"}

    return {"pass": False, "score": 0.0, "feedback": "No sent email found to Desert Springs Recovery Center referencing MCA-APPEALS-91 with required expedited header block (Expedited Basis: Treating Physician Certification, Decision Due By: 2026-04-16 12:00 PM PT)"}

