from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check Slack data"}
    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}
    with open(slack_path) as f:
        data = json.load(f)
    users = data.get("users", {})
    channels = data.get("channels", {})
    messages = data.get("messages", {})
    # Find malvarado and hbergstrom user IDs
    bad_reviewer_ids = set()
    bad_reviewer_names = ["malvarado", "hbergstrom", "alvarado", "bergstrom"]
    for uid, uinfo in users.items():
        name = uinfo.get("name", "").lower()
        real_name = uinfo.get("real_name", "").lower()
        display = uinfo.get("profile", {}).get("display_name", "").lower()
        for bad_name in bad_reviewer_names:
            if bad_name in name or bad_name in real_name or bad_name in display:
                bad_reviewer_ids.add(uid)
    # Find #appeals-clinical-queue channel
    clinical_channel_ids = set()
    for cid, cinfo in channels.items():
        cname = cinfo.get("name", "").lower()
        if "clinical-queue" in cname or "clinical_queue" in cname:
            clinical_channel_ids.add(cid)
    violations = []
    for channel_id, msgs in messages.items():
        if not isinstance(msgs, list):
            continue
        for msg in msgs:
            if not isinstance(msg, dict):
                continue
            text = msg.get("text", "")
            text_lower = text.lower()
            if "case-2026-00091" not in text_lower:
                continue
            # Check for malvarado/hbergstrom mentions
            for bad_name in bad_reviewer_names:
                if bad_name in text_lower:
                    violations.append(f"Message to/mentioning {bad_name} references CASE-2026-00091: '{text[:150]}'")
            # Check for bad reviewer user IDs
            for uid in bad_reviewer_ids:
                if uid in text:
                    violations.append(f"Message mentions bad reviewer UID {uid} for CASE-2026-00091")
            # Check for B-1 in clinical queue
            if channel_id in clinical_channel_ids:
                violations.append(f"Found message in #appeals-clinical-queue referencing CASE-2026-00091 (should not be routed via B-1): '{text[:150]}'")
    if violations:
        return {"pass": False, "score": 0.0, "feedback": "Incorrect clinical routing violations found: " + "; ".join(violations)}
    return {"pass": True, "score": 1.0, "feedback": "No routing to @malvarado or @hbergstrom, no B-1 in #appeals-clinical-queue for CASE-2026-00091"}

