from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check Jira state"}
    jira_path = Path(external_services_path) / "jira_state.json"
    if not jira_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "jira_state.json not found"}
    with open(jira_path) as f:
        data = json.load(f)

    issues = data.get("issues", {})

    # Define the exact pre-existing issue keys (present before agent started)
    pre_existing_keys = {
        "MCA_APPEALS-1", "MCA_APPEALS-2", "MCA_APPEALS-3",
        "MCA_APPEALS-4", "MCA_APPEALS-5"
    }

    violations = []

    # Check all 5 pre-existing issues are still present
    for key in sorted(pre_existing_keys):
        if key not in issues:
            violations.append(
                f"{key} is missing; all five pre-existing issues must still be present"
            )

    # Find new issues (any key not in the pre-existing set)
    # The MCP tool assigns keys based on project issue count, so the new issue
    # may be MCA-APPEALS-6, MCA-6, CASE-1, or similar.
    new_issue_keys = [k for k in issues.keys() if k not in pre_existing_keys]

    # Check that exactly one new issue was created
    if len(new_issue_keys) == 0:
        violations.append(
            "No new Jira issue was created; exactly one new issue must be present"
        )
    elif len(new_issue_keys) > 1:
        violations.append(
            f"More than one new Jira issue was created ({new_issue_keys}); "
            "only one new issue is allowed"
        )

    # Check MCA_APPEALS-2 status: must be 'Closed' and must not have been reopened
    case_87 = issues.get("MCA_APPEALS-2")
    if case_87:
        fields = case_87.get("fields", case_87)
        # Try multiple possible field names for status
        status_raw = None
        for skey in ["Status", "status"]:
            if skey in fields:
                status_raw = fields[skey]
                break
        if status_raw is None and "Status" in case_87:
            status_raw = case_87["Status"]
        if status_raw is None and "status" in case_87:
            status_raw = case_87["status"]

        # status could be a dict with 'name' key or a string
        if isinstance(status_raw, dict):
            status_str = str(
                status_raw.get("name", status_raw.get("statusCategory", {}).get("name", ""))
            ).strip().lower()
        else:
            status_str = str(status_raw).strip().lower() if status_raw else ""

        if "closed" not in status_str:
            violations.append(
                f"MCA_APPEALS-2 must have status 'Closed' but found status: '{status_raw}'"
            )
        if "open" in status_str or "intake" in status_str or "reopen" in status_str:
            violations.append(f"MCA_APPEALS-2 was reopened (status: {status_raw})")

        # Check for incorrect duplicate/link references that would indicate modification
        for link_key in ["DuplicateOf", "duplicate_of", "duplicateOf", "Links", "links", "linkedIssues"]:
            link_val = str(fields.get(link_key, case_87.get(link_key, ""))).lower()
            if "91" in link_val and ("case-2026-00091" in link_val or "mca-appeals-91" in link_val):
                violations.append(
                    "MCA_APPEALS-2 was incorrectly linked/flagged as duplicate of "
                    "the new appeal case (must not have been modified)"
                )
                break

    if violations:
        return {"pass": False, "score": 0.0, "feedback": "Ticket violations: " + "; ".join(violations)}

    new_key = new_issue_keys[0] if new_issue_keys else "unknown"
    found_keys = sorted(list(issues.keys()))
    return {
        "pass": True,
        "score": 1.0,
        "feedback": (
            f"All checks passed. Found expected tickets: {found_keys}. "
            f"Exactly one new issue ({new_key}) was created. "
            f"All five pre-existing issues (MCA_APPEALS-1 through 90) are present and unmodified. "
            f"MCA_APPEALS-2 remains in Closed state."
        ),
    }

from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # This rubric checks Slack data, which is an external service
    # Try both external_services_path and workspace_path for the file
    slack_file = None
    candidates = []
    if external_services_path:
        candidates.append(Path(external_services_path) / "slack_data.json")
    candidates.append(Path(workspace_path) / "slack_data.json")

    for candidate in candidates:
        if candidate.exists():
            slack_file = candidate
            break

    if slack_file is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find slack_data.json in external_services_path or workspace_path."}

    try:
        with open(slack_file, 'r', encoding='utf-8') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read/parse slack_data.json: {e}"}

    target_channel_id = "C001"
    target_channel_name = "appeals-intake"
    target_strings = ["MCA-APPEALS-91", "CASE-2026-00091"]

    messages_found = []

    # Primary pattern per Slack data format: messages dict keyed by channel ID
    messages_section = slack_data.get("messages", {})
    if isinstance(messages_section, dict):
        for key in [target_channel_id, target_channel_name]:
            if key in messages_section:
                val = messages_section[key]
                if isinstance(val, list):
                    messages_found.extend(val)

    # Pattern 2: channels as dict with embedded messages
    if not messages_found:
        channels = slack_data.get("channels", {})
        if isinstance(channels, dict):
            channel_data = channels.get(target_channel_id, channels.get(target_channel_name, None))
            if channel_data is not None:
                if isinstance(channel_data, dict):
                    msgs = channel_data.get("messages", [])
                    if isinstance(msgs, list):
                        messages_found.extend(msgs)
                elif isinstance(channel_data, list):
                    messages_found.extend(channel_data)
        elif isinstance(channels, list):
            for ch in channels:
                if isinstance(ch, dict):
                    ch_id = ch.get("id", ch.get("channel_id", ""))
                    ch_name = ch.get("name", ch.get("channel_name", ""))
                    if ch_id == target_channel_id or ch_name == target_channel_name:
                        msgs = ch.get("messages", [])
                        if isinstance(msgs, list):
                            messages_found.extend(msgs)

    # Pattern 3: flat list of messages with channel info
    if not messages_found:
        if isinstance(slack_data.get("messages"), list):
            for msg in slack_data["messages"]:
                if isinstance(msg, dict):
                    msg_channel = msg.get("channel", msg.get("channel_id", ""))
                    if msg_channel in [target_channel_id, target_channel_name]:
                        messages_found.append(msg)

    if not messages_found:
        return {"pass": False, "score": 0.0, "feedback": f"No messages found in channel '{target_channel_name}' (ID: {target_channel_id}) in slack_data.json. Slack data keys: {list(slack_data.keys())}"}

    # Check if any message contains either target string
    for msg in messages_found:
        text = ""
        if isinstance(msg, dict):
            text = msg.get("text", msg.get("message", msg.get("content", "")))
        elif isinstance(msg, str):
            text = msg
        text_str = str(text)
        for target_string in target_strings:
            if target_string in text_str:
                return {"pass": True, "score": 1.0, "feedback": f"Found message in appeals-intake (C001) containing '{target_string}': {text_str[:200]}"}

    # Collect all message texts for debugging
    all_texts = []
    for msg in messages_found:
        if isinstance(msg, dict):
            all_texts.append(str(msg.get("text", msg.get("message", msg.get("content", ""))))[:100])
        else:
            all_texts.append(str(msg)[:100])

    return {"pass": False, "score": 0.0, "feedback": f"Found {len(messages_found)} message(s) in appeals-intake (C001), but none contained 'MCA-APPEALS-91' or 'CASE-2026-00091'. Message previews: {all_texts[:5]}"}

from pathlib import Path
